using Contoso.Services;

namespace Contoso.Services.Tests;

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_And_Resolve_Returns_RegisteredInstance()
    {
        var service = new FakeLogger();

        _registry.Register<ILogger>(service);

        Assert.IsInstanceOfType<ILogger>(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Resolve_Returns_Same_Instance_That_Was_Registered()
    {
        var service = new FakeLogger();

        _registry.Register<ILogger>(service);

        Assert.AreSame(service, _registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Resolve_Returns_Null_For_Unregistered_Service()
    {
        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Clear_Removes_All_Services()
    {
        _registry.Register<ILogger>(new FakeLogger());
        _registry.Register<INotifier>(new FakeNotifier());

        _registry.Clear();

        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Remove_Makes_Service_Unresolvable()
    {
        _registry.Register<ILogger>(new FakeLogger());

        _registry.Remove<ILogger>();

        Assert.IsNull(_registry.Resolve<ILogger>());
    }

    [TestMethod]
    public void Register_Null_Throws_ArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _registry.Register<ILogger>(null!));
    }

    [TestMethod]
    public void ResolveRequired_Throws_When_Not_Registered()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _registry.ResolveRequired<ILogger>());
    }

    // Test doubles
    private interface ILogger { }
    private interface INotifier { }
    private sealed class FakeLogger : ILogger { }
    private sealed class FakeNotifier : INotifier { }
}

